class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    products = graphene.List(lambda: Product)

    def resolve_products(self, info):
        return [Product(**p) for p in products_data if p['category_id'] == self.id]


class Review(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user_name = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()
    created_at = graphene.DateTime()
    product = graphene.Field(lambda: Product)

    def resolve_product(self, info):
        product = next((p for p in products_data if p['id'] == self.product_id), None)
        return Product(**product) if product else None


class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()
    stock = graphene.Int()
    created_at = graphene.DateTime()
    category = graphene.Field(Category)
    reviews = graphene.List(Review)
    average_rating = graphene.Float()

    def resolve_category(self, info):
        category = next((c for c in categories_data if c['id'] == self.category_id), None)
        return Category(**category) if category else None

    def resolve_reviews(self, info):
        return [Review(**r) for r in reviews_data if r['product_id'] == self.id]

    def resolve_average_rating(self, info):
        product_reviews = [r for r in reviews_data if r['product_id'] == self.id]
        if not product_reviews:
            return None
        total_rating = sum(r['rating'] for r in product_reviews)
        return round(total_rating / len(product_reviews), 2)


class Query(graphene.ObjectType):
    products = graphene.List(
        Product,
        category_id=graphene.ID(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        search=graphene.String()
    )
    product = graphene.Field(Product, id=graphene.ID(required=True))
    
    categories = graphene.List(Category)
    category = graphene.Field(Category, id=graphene.ID(required=True))
    
    reviews = graphene.List(
        Review,
        product_id=graphene.ID(),
        min_rating=graphene.Int()
    )
    review = graphene.Field(Review, id=graphene.ID(required=True))

    def resolve_products(self, info, category_id=None, min_price=None, max_price=None, search=None):
        result = products_data.copy()
        
        if category_id:
            result = [p for p in result if p['category_id'] == category_id]
        
        if min_price is not None:
            result = [p for p in result if p['price'] >= min_price]
        
        if max_price is not None:
            result = [p for p in result if p['price'] <= max_price]
        
        if search:
            search_lower = search.lower()
            result = [p for p in result if search_lower in p['name'].lower() or search_lower in p['description'].lower()]
        
        return [Product(**p) for p in result]

    def resolve_product(self, info, id):
        product = next((p for p in products_data if p['id'] == id), None)
        return Product(**product) if product else None

    def resolve_categories(self, info):
        return [Category(**c) for c in categories_data]

    def resolve_category(self, info, id):
        category = next((c for c in categories_data if c['id'] == id), None)
        return Category(**category) if category else None

    def resolve_reviews(self, info, product_id=None, min_rating=None):
        result = reviews_data.copy()
        
        if product_id:
            result = [r for r in result if r['product_id'] == product_id]
        
        if min_rating is not None:
            result = [r for r in result if r['rating'] >= min_rating]
        
        return [Review(**r) for r in result]

    def resolve_review(self, info, id):
        review = next((r for r in reviews_data if r['id'] == id), None)
        return Review(**review) if review else None


class CreateReview(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        user_name = graphene.String(required=True)
        rating = graphene.Int(required=True)
        comment = graphene.String()

    review = graphene.Field(Review)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, product_id, user_name, rating, comment=None):
        if rating < 1 or rating > 5:
            return CreateReview(success=False, message="Rating must be between 1 and 5", review=None)
        
        product = next((p for p in products_data if p['id'] == product_id), None)
        if not product:
            return CreateReview(success=False, message="Product not found", review=None)
        
        new_review = {
            'id': str(len(reviews_data) + 1),
            'product_id': product_id,
            'user_name': user_name,
            'rating': rating,
            'comment': comment or '',
            'created_at': datetime.now().isoformat()
        }
        reviews_data.append(new_review)
        
        return CreateReview(success=True, message="Review created successfully", review=Review(**new_review))


class UpdateProduct(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)
        name = graphene.String()
        description = graphene.String()
        price = graphene.Float()
        stock = graphene.Int()

    product = graphene.Field(Product)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, id, name=None, description=None, price=None, stock=None):
        product = next((p for p in products_data if p['id'] == id), None)
        if not product:
            return UpdateProduct(success=False, message="Product not found", product=None)
        
        if name is not None:
            product['name'] = name
        if description is not None:
            product['description'] = description
        if price is not None:
            product['price'] = price
        if stock is not None:
            product['stock'] = stock
        
        return UpdateProduct(success=True, message="Product updated successfully", product=Product(**product))


class Mutation(graphene.ObjectType):
    create_review = CreateReview.Field()
    update_product = UpdateProduct.Field()


schema = graphene.Schema(query=Query, mutation=Mutation)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True
    )
)

